import * as os from "node:os";
import * as path from "node:path";
import type { ExtensionAPI, ExtensionContext } from "@mariozechner/pi-coding-agent";

const EXTENSION_TYPE = "paths-from-env";
const WORKSPACE_ROOT = path.join(os.homedir(), "workspace");

const KNOWN_PATH_VARS: ReadonlyArray<readonly [string, string]> = [
	["Language spec", "PI_LANG_SPEC"],
	["Test directory", "PI_TEST_DIR"],
	["Build directory", "PI_BUILD_DIR"],
];

type PathHint = {
	label: string;
	envName: string;
	value: string;
};

function isWorkspaceProject(cwd: string): boolean {
	return cwd === WORKSPACE_ROOT || cwd.startsWith(`${WORKSPACE_ROOT}${path.sep}`);
}

function humanizeEnvName(envName: string): string {
	return envName
		.replace(/^PI_(PATH|RESOURCE)_/, "")
		.toLowerCase()
		.split("_")
		.filter(Boolean)
		.map((word) => word[0].toUpperCase() + word.slice(1))
		.join(" ");
}

function collectPathHints(): PathHint[] {
	const hints: PathHint[] = [];
	const seen = new Set<string>();

	for (const [label, envName] of KNOWN_PATH_VARS) {
		const value = process.env[envName]?.trim();
		if (!value) {
			continue;
		}

		hints.push({ label, envName, value });
		seen.add(envName);
	}

	for (const [envName, rawValue] of Object.entries(process.env).sort(([a], [b]) => a.localeCompare(b))) {
		const value = rawValue?.trim();
		if (!value || seen.has(envName)) {
			continue;
		}

		if (!envName.startsWith("PI_PATH_") && !envName.startsWith("PI_RESOURCE_")) {
			continue;
		}

		hints.push({
			label: humanizeEnvName(envName),
			envName,
			value,
		});
	}

	return hints;
}

function hasInjectedMessage(ctx: ExtensionContext): boolean {
	return ctx.sessionManager
		.getBranch()
		.some((entry) => entry.type === "custom_message" && entry.customType === EXTENSION_TYPE);
}

function buildMessage(hints: PathHint[]): string {
	const lines = hints.map(({ label, envName, value }) => `- ${label} (\`${envName}\`): \`${value}\``).join("\n");

	return `Canonical path hints loaded from environment for this session:

${lines}

Treat these as the preferred resource paths when relevant.`;
}

function buildClearedMessage(): string {
	return "No canonical path hints are currently loaded from the environment. Ignore any earlier path hints from this extension.";
}

function injectPathHints(pi: ExtensionAPI, ctx: ExtensionContext, source: "session_start" | "paths_refresh", allowEmpty: boolean): number {
	const hints = collectPathHints();
	if (hints.length === 0 && !allowEmpty) {
		return 0;
	}

	pi.sendMessage({
		customType: EXTENSION_TYPE,
		content: hints.length > 0 ? buildMessage(hints) : buildClearedMessage(),
		display: true,
		details: {
			workspaceRoot: WORKSPACE_ROOT,
			source,
			empty: hints.length === 0,
			hints: hints.map(({ label, envName, value }) => ({ label, envName, value })),
		},
	}, ctx.isIdle() ? undefined : { deliverAs: "nextTurn" });

	return hints.length;
}

export default function pathsFromEnv(pi: ExtensionAPI) {
	pi.on("session_start", async (_event, ctx) => {
		if (!isWorkspaceProject(ctx.cwd) || hasInjectedMessage(ctx)) {
			return;
		}

		const hintCount = injectPathHints(pi, ctx, "session_start", false);
		if (hintCount === 0) {
			return;
		}

		if (ctx.hasUI) {
			ctx.ui.notify(`Loaded ${hintCount} path hint(s) from environment`, "info");
		}
	});

	pi.on("context", async (event) => {
		let keepLatest = true;
		const messages = [...event.messages]
			.reverse()
			.filter((message) => {
				if (message.role !== "custom" || message.customType !== EXTENSION_TYPE) {
					return true;
				}

				if (keepLatest) {
					keepLatest = false;
					return true;
				}

				return false;
			})
			.reverse();

		return { messages };
	});

	pi.registerCommand("paths-refresh", {
		description: "Reload canonical path hints from environment variables",
		handler: async (_args, ctx) => {
			if (!isWorkspaceProject(ctx.cwd)) {
				ctx.ui.notify(`paths-from-env is only active under ${WORKSPACE_ROOT}`, "warning");
				return;
			}

			const hintCount = injectPathHints(pi, ctx, "paths_refresh", true);
			if (hintCount > 0) {
				ctx.ui.notify(
					ctx.isIdle()
						? `Refreshed ${hintCount} path hint(s) from environment`
						: `Queued ${hintCount} refreshed path hint(s) for the next prompt`,
					"info",
				);
				return;
			}

			ctx.ui.notify(
				ctx.isIdle()
					? "Cleared path hints for future prompts"
					: "Queued path hint clearing for the next prompt",
				"info",
			);
		},
	});
}

